  ('colonel-d0d1b9a2-moex-00058', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-112-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司出售電腦產生銷貨收入$12,000，這批電腦提供保證型保固服務，估 計因保固服務而產生之成本為銷貨收入之2%，甲公司應：', '["省略對保固費用之會計處理，因為只有2%", "一律在保固修理工作完成時，認列保固費用，以符合配合原則", "一律將保固費用視為或有負債，附註揭露即可", "一律在銷貨收入產生當期認列保固費用與保固負債"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00059', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-112-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年度有以下相關資料： ⑴X1年1月1日期初應收帳款餘額$115,000，12月31日期末應收帳款餘 額$100,000 ⑵X1年12月31日公司宣布每股$0.05之股利，當日流通在外股票為 2,800,000股，並於X2年1月31日發放。公司於X0年並未宣布或發放任何 股利 ⑶以$5,000出售帳面金額$7,000之卡車，產生損失$2,000 ⑷支付公司債利息$780,000 ⑸X0年12月31日現金餘額$106,000，X1年12月31日現金餘額$284,000 試問甲公司營業活動現金流量、投資活動現金流量與籌資活動現金流量合 計為：', '["與X1年報導之淨利數相同", "現金流出$582,000", "現金流入$178,000", "現金流入$284,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
