  ('colonel-d0d1b9a2-moex-00063', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-111-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '按照財務報導之觀念架構，下列何種衡量基礎不須考量交易成本？①歷史成', '["現時成本", "公允價值", "資產之使用價值  ⑤負債之履約價值", "僅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
