  ('colonel-d0d1b9a2-moex-00065', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-111-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', 'X3 年初甲公司有 1,000,000 股普通股發行流通在外，4 月 1 日另發行 600,000股普通股，10月1日甲公司平價發行10,000張面值$1,000，8%的 可轉換公司債，每張公司債可轉換 40 股普通股。當時相同條件無轉換權 之公司債公允價值為$900，有效利率10%，X3年度並無轉換。甲公司X3 年度淨利為$5,800,000，所得稅率20%，則X3年稀釋每股盈餘為何？', '["$3.110", "$3.845", "$3.858", "$3.887"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00066', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-111-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司 7 月 31 日銀行對帳單上之存款餘額為$640,000，7 月底在途存款為 $90,000、未兌現支票為$120,000。7 月份因存款不足而退票$40,000，其中 $24,000 又於 7 月底前存入。7 月 30 日銀行誤將兌付丁公司之支票$35,000 誤自甲公司帳戶中扣除，銀行尚未發現此錯誤。7月份銀行代收票據$56,000 ，並扣除手續費$1,000。甲公司7月31日帳上之存款餘額是多少？', '["$606,000", "$614,000", "$574,000", "$590,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00067', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-111-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司X2年度綜合損益表中稅前淨利為$70,100，審計人員發現其中包含', '["透過其他綜合損益按公允價值衡量之債務工具投資未實現評 價損失$5,400；", "透過其他綜合損益按公允價值衡量之權益工具投資處分 利益$3,000；", "提前贖回債券利益$22,000；", "X1 年度少計提折舊之追溯 重編影響數$7,500；⑤火災損失$7,000。甲公司X2年度稅前淨利應為："]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL)
